import type React from "react";

import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "../utils/cn";

const timeSegmentVariants = cva("inline-block h-full", {
  variants: {
    state: {
      runtime: "bg-load-state-runtime",
      idle: "bg-load-state-idle",
      offline: "bg-load-state-offline",
      planned: "bg-load-state-planned",
      nodata: "bg-load-state-nodata",
    },
  },
  defaultVariants: {
    state: "nodata",
  },
});

interface TimeSegmentOwnProps {
  /** Load state controlling the segment color. */
  state: "runtime" | "idle" | "offline" | "planned" | "nodata";
  /** Width as a percentage of the parent container (0-100). */
  widthPercent: number;
  /** Optional label shown as a tooltip (title attribute). */
  label?: string;
}

type TimeSegmentProps = Omit<React.ComponentProps<"span">, "title"> &
  TimeSegmentOwnProps;

/**
 * A pure CSS colored bar representing a time period in a timeline.
 *
 * Place multiple TimeSegments inside a flex container to compose
 * a full timeline bar (e.g., a 24-hour Gantt row).
 */
function TimeSegment({
  className,
  state,
  widthPercent,
  label,
  ...props
}: TimeSegmentProps) {
  return (
    <span
      data-slot="time-segment"
      className={cn(timeSegmentVariants({ state }), className)}
      style={{ width: `${widthPercent}%`, minWidth: "1px" }}
      title={label}
      {...props}
    />
  );
}

export { TimeSegment, timeSegmentVariants };
export type { TimeSegmentProps };
